import React from "react";
import "./Hero.css";
import phpImage from "../../assets/img/php.png";
import myImage from "../../assets/img/myimg.jpeg";
import codeigniterImage from "../../assets/img/codeigniter.svg";
import linuxImage from "../../assets/img/linux.svg";
import awsImage from "../../assets/img/aws.png";
import wordpressImage from "../../assets/img/wordpress.png";
import logoImage from "../../logo192.png";

function Hero() {
  return (
    <>
      <section id="home-container" className="hero-container">
        <div className="hero-content">
          <h2>Building Digital Experience that inspire</h2>
          <p>
            Passionate Software Quality Assurance Engineer | Transform idea into Seamless and
            Visually Stunning Web Application
          </p>
        </div>
        <div className="hero-img">
          <div>
            <div className="tech-icon">
              <img src={phpImage} alt="PHP" />
            </div>
            <img src={myImage} alt="My Image" />
          </div>
          <div>
            <div className="tech-icon">
              <img src={codeigniterImage} alt="CodeIgniter" />
            </div>
            <div className="tech-icon">
              <img
                style={{ height: "3rem", width: "3rem" }}
                src={linuxImage}
                alt="Linux"
              />
            </div>
            <div className="tech-icon">
              <img src={awsImage} alt="AWS" />
            </div>
            <div className="tech-icon">
              <img src={wordpressImage} alt="WordPress" />
            </div>
            <div className="tech-icon">
              <img src={logoImage} alt="Logo" />
            </div>
          </div>
        </div>
      </section>
    </>
  );
}

export default Hero;
